import numpy as np

def batch_normalization(
    X: np.ndarray,
    gamma: np.ndarray,
    beta: np.ndarray,
    running_mean: np.ndarray = None,
    running_var: np.ndarray = None,
    momentum: float = 0.1,
    epsilon: float = 1e-5,
    training: bool = True
) -> tuple[np.ndarray, np.ndarray, np.ndarray]:
    B, C, H, W = X.shape

    if running_mean is None:
        running_mean = np.zeros((1, C, 1, 1))
    if running_var is None:
        running_var = np.ones((1, C, 1, 1))

    if training:
        # Compute mean and variance over (B, H, W) for each channel
        batch_mean = np.zeros((1, C, 1, 1))
        batch_var = np.zeros((1, C, 1, 1))
        N = B * H * W

        for c in range(C):
            channel_data = X[:, c, :, :]  # shape (B, H, W)
            total = 0.0
            for b in range(B):
                for h in range(H):
                    for w in range(W):
                        total += channel_data[b, h, w]
            mean_c = total / N
            batch_mean[0, c, 0, 0] = mean_c

            var_total = 0.0
            for b in range(B):
                for h in range(H):
                    for w in range(W):
                        diff = channel_data[b, h, w] - mean_c
                        var_total += diff * diff
            batch_var[0, c, 0, 0] = var_total / N

        # Normalize
        X_norm = np.zeros_like(X)
        for c in range(C):
            std = (batch_var[0, c, 0, 0] + epsilon) ** 0.5
            for b in range(B):
                for h in range(H):
                    for w in range(W):
                        X_norm[b, c, h, w] = (X[b, c, h, w] - batch_mean[0, c, 0, 0]) / std

        # Update running statistics
        running_mean = (1 - momentum) * running_mean + momentum * batch_mean
        running_var = (1 - momentum) * running_var + momentum * batch_var

    else:
        # Use running statistics for inference
        X_norm = np.zeros_like(X)
        for c in range(C):
            std = (running_var[0, c, 0, 0] + epsilon) ** 0.5
            for b in range(B):
                for h in range(H):
                    for w in range(W):
                        X_norm[b, c, h, w] = (X[b, c, h, w] - running_mean[0, c, 0, 0]) / std

    # Scale and shift
    output = gamma * X_norm + beta
    return output, running_mean, running_var
